def parse_args() -> argparse.Namespace:
    p = argparse.ArgumentParser(
        description="Submission-equivalent rain baseline on full val (no post-t10 dynamic leakage)."
    )
    p.add_argument("--config", required=True)
    p.add_argument("--seed", type=int, default=42)
    p.add_argument("--max_events_train", type=int, default=-1)
    p.add_argument("--max_events_val", type=int, default=-1)
    p.add_argument("--max_samples_train", type=int, default=-1)
    p.add_argument("--max_samples_val", type=int, default=-1)
    p.add_argument(
        "--cache_dir",
        type=str,
        default="cache/xgb",
        help="Base directory for feature and OOF caches.",
    )
    p.add_argument(
        "--cache_features",
        action="store_true",
        default=True,
        help="Cache base feature matrices/targets for reuse across ablations (default: on).",
    )
    p.add_argument("--no_cache_features", action="store_false", dest="cache_features")
    p.add_argument(
        "--cache_stage_a_oof",
        action="store_true",
        default=True,
        help="Cache stage-A OOF predictions (qnet/qinout/aux) for reuse across runs (default: on).",
    )
    p.add_argument("--no_cache_stage_a_oof", action="store_false", dest="cache_stage_a_oof")
    p.add_argument(
        "--cache_overwrite",
        action="store_true",
        default=False,
        help="Force overwrite existing cache entries.",
    )
    p.add_argument(
        "--mem_log",
        action="store_true",
        default=True,
        help="Print lightweight memory snapshots at key pipeline stages (default: on).",
    )
    p.add_argument("--no_mem_log", action="store_false", dest="mem_log")
    p.add_argument(
        "--balanced_event_sampling",
        action="store_true",
        default=True,
        help="Distribute sample budget across events to avoid first-event dominance (default: on).",
    )
    p.add_argument(
        "--no_balanced_event_sampling",
        action="store_false",
        dest="balanced_event_sampling",
    )
    p.add_argument("--windows", type=str, default="1,2,4,8,16,32,64")
    p.add_argument("--alphas", type=str, default="0.9,0.97,0.99")
    p.add_argument("--static_dims", type=int, default=6)
    p.add_argument("--type_specific", action="store_true", default=True)
    p.add_argument("--no_type_specific", action="store_false", dest="type_specific")
    p.add_argument(
        "--backend",
        type=str,
        default="xgboost_gpu",
        choices=["xgboost_gpu", "xgboost_cpu", "lightgbm", "catboost", "sklearn", "elasticnet", "elasticnet_cv"],
        help="Regressor backend for baseline fitting (default: xgboost_gpu).",
    )
    p.add_argument("--xgb_reg_n_estimators", type=int, default=500)
    p.add_argument("--xgb_reg_learning_rate", type=float, default=0.05)
    p.add_argument("--xgb_reg_max_depth", type=int, default=6)
    p.add_argument("--xgb_reg_subsample", type=float, default=0.8)
    p.add_argument("--xgb_reg_colsample_bytree", type=float, default=0.8)
    p.add_argument("--xgb_reg_min_child_weight", type=float, default=1.0)
    p.add_argument("--xgb_reg_gamma", type=float, default=0.0)
    p.add_argument("--xgb_reg_reg_alpha", type=float, default=0.0)
    p.add_argument("--xgb_reg_reg_lambda", type=float, default=1.0)
    p.add_argument("--xgb_cls_n_estimators", type=int, default=400)
    p.add_argument("--xgb_cls_learning_rate", type=float, default=0.05)
    p.add_argument("--xgb_cls_max_depth", type=int, default=5)
    p.add_argument("--xgb_cls_subsample", type=float, default=0.8)
    p.add_argument("--xgb_cls_colsample_bytree", type=float, default=0.8)
    p.add_argument("--xgb_cls_min_child_weight", type=float, default=1.0)
    p.add_argument("--xgb_cls_gamma", type=float, default=0.0)
    p.add_argument("--xgb_cls_reg_alpha", type=float, default=0.0)
    p.add_argument("--xgb_cls_reg_lambda", type=float, default=1.0)
    p.add_argument("--xgb_es_enable", action="store_true", default=False, help="Enable event-group early stopping for XGBoost models (stage-A OOF/base fits and stage-B two-stage fits).")
    p.add_argument("--no_xgb_es_enable", action="store_false", dest="xgb_es_enable")
    p.add_argument("--xgb_es_rounds", type=int, default=50, help="Early stopping rounds for XGBoost when --xgb_es_enable.")
    p.add_argument("--xgb_es_val_frac", type=float, default=0.1, help="Validation fraction of unique events used for event-group XGBoost early stopping.")
