            if fe_tslr_features:
                rh_all = np.asarray(rain_hist_all, dtype=np.float32)
                n_hist = int(rh_all.shape[0])
                if n_hist > 0:
                    rain_now_arr = rh_all[-1, :].astype(np.float32, copy=False)
                else:
                    rain_now_arr = np.zeros((n_nodes,), dtype=np.float32)
                eps_rain = 1e-8
                nz_now = rh_all > eps_rain
                has_rain = np.any(nz_now, axis=0)
                if n_hist > 0:
                    last_from_end = np.argmax(nz_now[::-1, :], axis=0).astype(np.float32, copy=False)
                    tslr_local = np.where(has_rain, last_from_end, float(n_hist)).astype(np.float32, copy=False)
                else:
                    tslr_local = np.zeros((n_nodes,), dtype=np.float32)
                tslr_local_log1p = np.log1p(tslr_local).astype(np.float32, copy=False)
                tslr_up_mean = _upstream_agg(tslr_local, use_mean=True).astype(np.float32, copy=False)
                tslr_up_minus_local = (tslr_up_mean - tslr_local).astype(np.float32, copy=False)
                tslr_is_dry_now = (rain_now_arr <= eps_rain).astype(np.float32, copy=False)
                if n_hist >= 2:
                    rain_prev_arr = rh_all[-2, :].astype(np.float32, copy=False)
                    nz_prev = rh_all[:-1, :] > eps_rain
                    has_prev_rain = np.any(nz_prev, axis=0)
                    prev_last_from_end = np.argmax(nz_prev[::-1, :], axis=0).astype(np.float32, copy=False)
                    tslr_prev = np.where(has_prev_rain, prev_last_from_end, float(n_hist - 1)).astype(np.float32, copy=False)
                    tslr_reset = (
                        (rain_now_arr > eps_rain)
                        & (rain_prev_arr <= eps_rain)
                        & (tslr_prev >= 1.0)
                    ).astype(np.float32, copy=False)
                else:
                    tslr_reset = np.zeros((n_nodes,), dtype=np.float32)
                tslr_inlet_x = (tslr_local * is_inlet_1d_static).astype(np.float32, copy=False)
                tslr_outfall_x = (tslr_local * is_outfall_1d_static).astype(np.float32, copy=False)
            if fe_upstream_hist_ema_features:
                rh_all = np.asarray(rain_hist_all, dtype=np.float32)
