    def _collect_with_feature_cache(ds, split_tag: str, event_limit: int, max_samples: int):
        payload = dict(feature_cache_common)
        payload.update(
            {
                "split": split_tag,
                "event_limit": int(event_limit),
                "max_samples": int(max_samples),
                "root_dir": str(getattr(ds, "root_dir", "")),
                "n_events": int(len(getattr(ds, "hec_ras_run_ids", []))),
            }
        )
        key = _stable_cache_key("basefeat", payload)
        cache_path = _cache_feature_npz_path(args.cache_dir, key, split_tag)
        if bool(args.cache_features):
            z = _load_npz_if_exists(cache_path)
            if z is not None and (not bool(args.cache_overwrite)):
                print(f"[CACHE_HIT] stage=base_features split={split_tag} path={cache_path}", flush=True)
                return (
                    z["X"],
                    z["y"],
                    z["y_qnet"],
                    z["y_base"],
                    z["nt"],
                    z["nid"],
                    z["eid"],
                    z["tr"],
                    z["nidx"],
                    z["es"],
                    key,
                )
